'use strict';

const path = require('path');
const fs = require('fs');

// Load problems data once
const problemsDataPath = path.resolve(__dirname, '../../data/problems.json');
let problemsData = [];
try {
  const rawData = fs.readFileSync(problemsDataPath, 'utf8');
  problemsData = JSON.parse(rawData);
} catch (e) {
  // If file read fails, keep problemsData empty
  problemsData = [];
}

/**
 * Get problem details by problemId including component statistics.
 * @param {string|number} problemId
 * @return {object|null} problem details with component stats or null if not found
 */
function getProblemDetails(problemId) {
  const pid = String(problemId);
  const problem = problemsData.find(p => String(p.problemId) === pid);
  if (!problem) return null;

  // Aggregate component statistics
  const components = problem.components || [];
  const languageCounts = {};
  const statusCounts = {};
  let maxPoints = 0;

  components.forEach(comp => {
    if (comp.language) {
      languageCounts[comp.language] = (languageCounts[comp.language] || 0) + 1;
    }
    if (comp.status) {
      statusCounts[comp.status] = (statusCounts[comp.status] || 0) + 1;
    }
    if (typeof comp.points === 'number' && comp.points > maxPoints) {
      maxPoints = comp.points;
    }
  });

  return {
    ...problem,
    componentStats: {
      languageCounts,
      statusCounts,
      maxPoints,
    },
  };
}

module.exports = {
  getProblemDetails,
};
